var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이게 전부인가요?","JPN":"これで終わりですか？","ENG":"Is that all?","TWN":"這就完了嗎？"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"큰소리친 것에 비해선, 그냥 그런저런 수준이로군요.","JPN":"大口を叩いていた割には、そう大したことないですね。","ENG":"Compared to all your boasting, your skills are average at best.","TWN":"吹牛吹得那麼厲害，結果也不過如此嘛。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"쳇, 너야말로 나풀나풀 도망치면서 간만 보고 있잖아.","JPN":"ちっ、あんたこそヒラヒラ逃げ回りながら様子を見てるだけじゃん。","ENG":"Tch. Says the one who keeps running away.","TWN":"嘖，你才是一直在一邊逃跑一邊觀察情況的吧。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"제대로 할 생각이 있긴 한 거야, 간잽이?","JPN":"ちゃんとやる気あんの？","ENG":"Are you even taking this seriously, you schemer?","TWN":"你到底能不能認真點？"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"말씀드렸을 텐데요. 이건 훈련이 아니라, 훈육이라고요.","JPN":"言ったはずです。これは訓練ではなく、訓育だと。","ENG":"I told you beforehand. This is discipline, not training.","TWN":"我應該說過，這不是訓練，而是教導。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"훈육이든, 훈제 연어든 내가 알 바……","JPN":"訓育だか燻製だか、そんなのアタシの知ったことじゃ……","ENG":"Discipline or disco, like I care–","TWN":"我管你是教導還是教室呢，跟我有什麼……"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"으음?","JPN":"ううん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"크윽, 발 밑에 깔아둔 종이들이 발에 휘감겨서……!?","JPN":"くっ、足の下に敷かれた紙が足に巻きついてる……！？","ENG":"Kgh, the papers below me tangled my feet...?!","TWN":"呃，腳下的紙纏住了腳……？！"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"제 카운터 능력이랍니다.","JPN":"私のカウンター能力です。","ENG":"This is my Counter ability.","TWN":"這是我的制裁者能力。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"CRF를 제어해서 종이를 강철처럼 단단하게 만들거나, 고무처럼 부드럽게 만들 수 있죠.","JPN":"CRFを制御して紙を鋼のように硬くしたり、ゴムのように柔らかくすることもできるんです。","ENG":"I am able to control the CRF to make paper as hard as steel or as soft as rubber.","TWN":"透過控制CRF，可以讓紙張像鋼鐵一樣堅硬，或者像橡膠一樣柔軟。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"또한 형태가 자유로운 종이라면…….","JPN":"さらに、形が自由な紙なら……","ENG":"Also, since the paper can be freely reformed...","TWN":"如果是形狀多變的紙張……"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이런 식으로도 활용할 수 있습니다.","JPN":"こんな風にも活用できます。","ENG":"I am capable of utilizing it like this.","TWN":"也可以這樣利用。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"종이를 뭉쳐서… 검을 만들었어……?","JPN":"紙をひとかたまりにして……剣を作った……？","ENG":"You bunched up some paper... and turned it into a sword...?","TWN":"把紙揉成團……做成了劍……？"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L29_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"큭. 비겁하게 멀리서 쏘아대면, 가까이 갈 수가 없잖아!","JPN":"くっ。卑怯だね。遠くから撃つなんて、近づけないじゃん！","ENG":"Kgh. How am I supposed to get close to you if you keep cowardly shooting from afar?!","TWN":"喂！你要是一直躲在遠處偷偷放冷槍，我怎麼靠近得了你啊！"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"기억하세요. 이건 비겁한 게 아니라, CRF 제어에 따른 능력 활용이라는 겁니다.","JPN":"覚えておきなさい。これは卑怯なことではなく、CRF制御による能力の活用なのです。","ENG":"Remember. This is not cowardice, but my controlling the CRF according to my ability.","TWN":"記住，這不是放冷槍，而是根據CRF控制來解放能力。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신에 관해서는 전부 읽었습니다, 시스터 루퍼.","JPN":"あなたに関する資料は全部読みました、シスター・ルーパー。","ENG":"Sister Looper, I have read everything about you.","TWN":"我說過，關於你的一切我都了解過了，洛珀姊妹。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신의 카운터 능력은 워치에서 전기톱 형태의 무기를 만들어내는 것.","JPN":"あなたのカウンター能力はウォッチからチェーンソー形態の武器を作り出すこと。","ENG":"Your Counter ability is manifesting an electric chainsaw-like weapon from your Watch.","TWN":"你的制裁者能力是從能量環中製造出電鋸形態的武器。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"틀림없이 당신이 자주 보던 불경한 영상물이 카운터 능력 발현의 트리거로 작용했겠죠.","JPN":"きっとあなたがよく見ていた不敬な映像が、カウンター能力発現のトリガーになったのでしょう。","ENG":"I have no doubt those blasphemous videos you frequently enjoy acted as a trigger for your Counter ability manifestation.","TWN":"毫無疑問，你經常觀看那些不入流的影片，這些影片肯定成為了觸發你制裁者能力的來源。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"시끄러워……!!","JPN":"うるさい……！！","ENG":"Shut up...!!","TWN":"閉嘴……！！"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"확실히. 전기톱의 궤적이 그럭저럭 급소를 향하고 있군요.","JPN":"確かに。チェーンソーの軌跡がまあまあ急所を狙ってはいますね。","ENG":"Surely, the chainsaw's trajectory is roughly aimed at a vital point.","TWN":"確實，電鋸的軌跡還算準確地指向了要害。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"CRF로 향상된 신체 능력과 전기톱을 무기로 사용하는 저돌적인 근접 전투…….","JPN":"CRFにより向上された身体能力とチェーンソーを武器として使用する猪突猛進な近接戦闘……","ENG":"Daring close-quarter combat with physical abilities enhanced by CRF with a chainsaw as your weapon...","TWN":"透過CRF提升身體能力，以電鋸為武器，魯莽近戰……"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이 정도 위력이라면, 일반적인 침식체의 갑피를 절단하는 데는 큰 문제가 없을 겁니다.","JPN":"これほどの威力なら、一般的な侵食体の甲皮を切断することは問題ないでしょう。","ENG":"With this amount of power, you will have no trouble cutting through the armor of a typical C.O.","TWN":"這種威力的話，切斷一般的侵蝕體外殼應該沒什麼問題。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만…….","JPN":"ですが……","ENG":"However...","TWN":"但是……"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"제길. 종이로 전기톱의 몸체 부분을 빗겨쳐다니……!","JPN":"くそ。紙でチェーンソーのガイドバーを当てて軌道をそらすなんて……！","ENG":"Crud. She's using the paper to deflect my chainsaw's blade...!","TWN":"該死，用紙躲開了電鋸的機身部分……！"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"이러면 제대로 맞추기가 힘들잖아.","JPN":"これだとまともに攻撃できない。","ENG":"I won't be able to get her at this rate.","TWN":"這樣的話很難瞄準啊。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"……크윽!!","JPN":"……くうっ！！","ENG":"...Kgh!!","TWN":"……咳呃！！"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_16"},{"id":"L1_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 능력의 활용이 너무 단순해요.","JPN":"ですが、能力の使い方が単純すぎますね。","ENG":"However, your use of your ability is too simple.","TWN":"但是能力的運用太單一了。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L2_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"제아무리 치명적인 공격이라고 해도, 결국 맞추지 못하면 소용없겠죠.","JPN":"いくら致命的な攻撃であっても、命中しないと意味がありません。","ENG":"No matter how deadly your attack may be, it is useless if it does not make contact.","TWN":"再致命的攻擊，如果打不中的話也沒用吧。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"……거, 싸우면서 쫑알쫑알 되게 시끄럽네. 싸움을 입으로 해?","JPN":"……もう、戦いながらブツブツうるさいな。口で戦ってるわけ？","ENG":"...Ugh, you're annoying me with all that talk! Do you think we're having a fight with words right now?!","TWN":"……喂，打架的時候嘰嘰喳喳的很吵欸。你是用嘴巴打架的嗎？"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"빨랑 제대로 덤비기나 하라고!","JPN":"早くちゃんとかかって来なよ！","ENG":"Stop talking and come at me for real!","TWN":"快點認真出招吧！"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"조금 더 머리를 써 보세요, 시스터 루퍼.","JPN":"もう少し頭を使ってください、シスター・ルーパー。","ENG":"Use your head, Sister Looper.","TWN":"再動動腦筋吧，洛珀姊妹。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그 능력을 어떻게 써야 할지, 그 톱날이 주의 적을 심판하려면 어떻게 해야 할지…….","JPN":"その能力をどう使うべきか、そのチェーンソーが主の敵を審判するためにはどうしたらいいのか……","ENG":"Think about how you should use your ability and how you can use that sawblade to judge the Lord's enemies...","TWN":"該如何使用那份能力，如何讓那鋸齒審判周圍的敵人……"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"실전에서는 찰나의 망설임이 소중한 사람을 잃게 만들 테니까요.","JPN":"実戦ではほんの少しの迷いが大切な人を失うという結果に繋がるのですから。","ENG":"In real combat, even the slightest hesitation can cost you the loss of someone precious.","TWN":"實戰中，片刻的猶豫會讓你失去重要的人。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그래요. 이를테면, 당신의 경우…….","JPN":"そうです。たとえば、あなたの場合……","ENG":"Yes. I suppose in your case...","TWN":"那好吧，比如說，你的情況是……"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"시스터 넬슨이 있겠군요. 진짜 자매처럼 꽤 돈독한 사이처럼 보이던데…….","JPN":"シスター・ネルソンになりますね。本当の姉妹のようにかなり仲良く見えますが……","ENG":"it would be Sister Nelson. It seemed you two were really close, like real sisters...","TWN":"尼爾森姊妹在這啊。看起來你們關係很好，像真正的姊妹一樣……"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"넬슨은 내가 지켜. 나한테서 넬슨을 뺏어가지 마.","JPN":"ネルソンはアタシが守る。アタシからネルソンを奪うなよ。","ENG":"Nelson's under my protection. You're not taking her away from me.","TWN":"我會保護尼爾森的，不要從我這裡奪走尼爾森。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……빈틈.","JPN":"……隙あり。","ENG":"...I see a gap.","TWN":"……有破綻。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"크학……!!","JPN":"ぐはっ……！！","ENG":"Ack...!!","TWN":"呃啊……！！"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"쉽게 감정을 드러내지 마세요. 집행 사제 실격입니다.","JPN":"容易く感情を露呈させないこと。執行司祭としては失格です。","ENG":"Do not reveal your emotions so easily. You are unqualified to be an Inquisitorial Priest.","TWN":"不要輕易流露感情，你會失去治理祭司的資格。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"CRF는 현실을 개변하는 힘…….","JPN":"CRFは現実を改変する力……","ENG":"CRF is the power to change reality...","TWN":"CRF是改變現實的力量……"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L24_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"달리 해석하면, 개인으로부터 세계에 미치는 영향력이라고도 할 수 있죠.","JPN":"別の解釈では、個人が世界に及ぼす影響力とも言えるでしょう。","ENG":"If one looks at it with another perspective, it also means the influence that an individual has on the world.","TWN":"換句話說，也可以說是個人對世界的影響力。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"따라서 카운터라 해도 저마다 정해진 CRF의 출력을 바꿀 가능성은 극히 낮을 겁니다.","JPN":"ですからカウンターだとしても、それぞれ決められたCRFの出力を変える可能性はとても低いはずです。","ENG":"Thus, no matter if one is a Counter, it is highly unlikely that their CRF output will change.","TWN":"因此，即使是制裁者，每個人改變既定CRF輸出的可能性也極低。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"하아, 하아……!","JPN":"はあ、はあ……！","ENG":"*Huff* *Huff*","TWN":"哈啊，哈啊……！"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"그래서 뭐? 지금 너보다 등급이 낮다고 시비 거는 거야?","JPN":"だから何？　あんたよりランクが低いってケンカ売ってるわけ？","ENG":"So what? Are you trying to pick a fight with me over having a lower grade than you?","TWN":"所以呢？你是在嘲笑我等級比你低嗎？"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"틀렸습니다. 시스터 루퍼.","JPN":"違います。シスター・ルーパー。","ENG":"You are wrong, Sister Looper.","TWN":"錯了，洛珀姊妹。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"왜냐하면 인간의 마음은 항상 성장하고, 고정관념은 언제나 깨지기 마련이니까요.","JPN":"何故なら、人間の心は常に成長して、固定観念はいつも壊されるものですからね。","ENG":"Because the human mind is always growing, and stereotypes will eventually be shattered.","TWN":"因為人的心靈總是在成長，固有觀念總是會被打破的。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"무슨 헛소리야, 그게?","JPN":"さっきから、なにうわごと言ってんだ？","ENG":"What's that supposed to mean?","TWN":"胡說八道什麼呢？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"카운터의 역량은 CRF의 출력이 전부가 아니에요.","JPN":"カウンターの力量はCRFの出力だけではありません。","ENG":"A Counter's capability is not all about their CRF output.","TWN":"制裁者的能力不僅僅是CRF的輸出。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그러니 지금보다 더 많은 걸 배우고, 느끼고, 경험하도록 하세요.","JPN":"ですからより多くのことを学んで、感じて、経験してください。","ENG":"So for now, I urge you to learn, feel, and experience more.","TWN":"所以請多學習、多感受、多經歷。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L35_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신 앞에 직면하게 될 현실을 어떻게 바꿀지는… 오롯이 당신에게 달려있으니까요.","JPN":"あなたが直面することになる現実をどう変えるかは……あなたにかかっていますから。","ENG":"For changing the reality that you will face... is entirely up to you.","TWN":"如何改變你即將面對的現實……完全取決於你自己。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>같은 시간</color>","JPN":"<color=#ffd34c>そのころ</color>","ENG":"<color=#ffd34c>Meanwhile</color>","TWN":"<color=#ffd34c>同一時間</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>성황청</color> 기적심의회 제9본부","JPN":"<color=#ffd34c>聖皇庁</color>奇跡審議会第9本部","ENG":"<color=#ffd34c>Holy Curia</color> Miracle Investigation Council 9's HQ","TWN":"<color=#ffd34c>聖皇廳</color> 奇蹟議會第9總部"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"어쩜 좋지…….","JPN":"どうしよう……","ENG":"What should I do...?","TWN":"怎麼辦……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L44_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"무슨 일인지는 잘 모르겠지만… 루체 자매님께서 화가 많이 난 것 같아 보였어…….","JPN":"どういうことかはわからないけど……シスター・ルーチェがとても怒っているように見えたね……","ENG":"I don't know what's going on, but... Sister Luce seemed really upset...","TWN":"雖然不太清楚發生了什麼事……但看起來露契姊妹非常生氣……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"분명, 루퍼 자매님이 뭔가 또 실례를…….","JPN":"きっと､シスター・シンディが何か失礼なことを……","ENG":"I'm sure Sister Looper had something to do with it...","TWN":"肯定是洛珀姊妹又做了什麼失禮的事……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"아아, 평소처럼 자매님 대신 죄송하다고 사과하는 편이 좋으려나……?","JPN":"ああ、いつもみたいにシスター・シンディの代わりに謝った方がいいのかしら……？","ENG":"Oh...! Maybe I should go apologize on behalf of Sister Looper like I always do...?","TWN":"啊啊，還是像平時一樣替她道個歉比較好吧……？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그치만 저렇게까지 화가 나신 걸 보면, 단순히 사과한다고 해결될 문제는 아닌 것 같아.","JPN":"でもあんなに怒っているのを見たら、謝ったところで解決できそうにないし。","ENG":"But seeing how furious she looked, I don't think a simple apology will resolve the situation.","TWN":"但是看她那麼生氣，光是道歉好像解決不了問題。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그럼, 어떡하지? 두 분 다 싸우지 않고 사이좋게 지냈으면 좋겠는데…….","JPN":"じゃあ、どうしよう？　お二人とも、ケンカしないで仲良くしてほしいけど……","ENG":"Then, what else should I do? I wish they would stop fighting and get along with each other...","TWN":"那怎麼辦呢？希望她們兩個不要打架，和睦相處……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"무슨 좋은 방법이 없을까?","JPN":"何かいい方法はないのかしら？","ENG":"I wonder if there is a good solution to this.","TWN":"沒有什麼好辦法嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"으음?","JPN":"うん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"저건……?","JPN":"あれは……？","ENG":"Is that...?","TWN":"那是……？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"이건… 크리스마스 트리잖아?","JPN":"これは……クリスマスツリーよね？","ENG":"It's... a Christmas tree?","TWN":"這是……聖誕樹嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"어머, 오랜만이네요, 넬슨 자매님.","JPN":"あら、お久しぶりですね。シスター・ネルソン。","ENG":"Oh, long time no see, Sister Nelson.","TWN":"天哪，好久不見了，尼爾森姊妹。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"지난 성무에서 크게 다치셨다고 들었는데… 이제 복귀해도 괜찮으신 건가요?","JPN":"この前の聖務で大怪我をしたと聞きましたけど……もう復帰してもいいのですか？","ENG":"I heard you were deeply injured from your last sacred mission. Are you now fit to be reinstated?","TWN":"聽說你在上次聖務中受了重傷……現在可以複職了嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"걱정해 주셔서 감사해요, 자매님.","JPN":"ご心配ありがとうございます、シスター。","ENG":"Thank you for your concerns, Sister.","TWN":"謝謝你的關心。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"저는 이제 다 나았답니다. 모두 자비로우신 주님께서 베푸신 은총이죠.","JPN":"私はもう大丈夫です。すべては慈しみ深い神の恵ですね。","ENG":"I'm all better now. It's all thanks to the blessing of the merciful Lord.","TWN":"我現在已經完全好了，這都是因為主的恩典。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그런데 이 트리는……?","JPN":"ところで、このツリーは……？","ENG":"But this tree...","TWN":"這棵樹是……？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"아하, 성탄절이 얼마 남지 않았잖아요.","JPN":"ああ、もうすぐ聖誕祭ではないですか。","ENG":"Oh, Christmas is just around the corner.","TWN":"啊哈，聖誕節快到了呢。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"심의회 분들은 보통 성무 때문에 바쁘시니까 분위기라도 낼 겸 해서요.","JPN":"審議会の皆さんは普段聖務でお忙しいですから、雰囲気でも出そうと思って。","ENG":"Since everyone at the Investigation Council is busy with sacred missions, I thought I'd bring a bit of holiday spirits to the place.","TWN":"議會的各位通常都忙於聖務，因此也想借此機會活絡一下氣氛。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"성탄절에는 모두가 행복해야 하니까요.","JPN":"聖誕祭はみんなが幸せでないとなりません。","ENG":"Everyone should be happy on Christmas, don't you think?","TWN":"聖誕節大家應該都會很開心。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그렇군요. 그러고 보니, 벌써 올해도 성탄절이 돌아왔네요.","JPN":"そうですね。そういえば、もう今年も聖誕祭がやってきました。","ENG":"I see. Come to think of it, I can't believe it's already that time of the year again.","TWN":"原來如此。說起來，又到了一年的聖誕節。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"작년에는 갑자기 발생한 침식 현상 때문에 성무를…… ","JPN":"昨年は急に発生した侵食現象で聖務を……","ENG":"Because of the sudden Counterside Effect that erupted last year–","TWN":"去年這時因為突然發生的侵蝕現象，聖務……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"엇!?","JPN":"あっ！？","ENG":"Huh?!","TWN":"啊？！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"넬슨 자매님? 왜 그러세요?","JPN":"シスター・ネルソン？　どうしたのですか？","ENG":"Sister Nelson? What’s wrong?","TWN":"尼爾森姊妹？怎麼了？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그래, 그렇구나! 성탄절이에요!","JPN":"そうか、それです！　聖誕祭です！","ENG":"Yes, that's it! Christmas!","TWN":"是啊！聖誕節到了！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"자매님 덕분에 두 자매님을 화해시킬 좋은 방법이 떠올랐어요!","JPN":"シスターのおかげで、お二人を仲直りさせるいい方法が思い浮かびました！","ENG":"I just thought of a brilliant solution to reconcile the two Sisters thanks to you!","TWN":"多虧了你，我想到了一個讓兩位姊妹和解的好辦法！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"두 자매님? 화해? 그게 무슨……?","JPN":"お二人？　仲直り？　それはどういう……？","ENG":"The two Sisters? Reconcile? What...?","TWN":"兩位姊妹？和解？那是什麼……？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"감사해요, 자매님! 이 또한 주님께서 베푸신 은총이겠죠!","JPN":"ありがとうございます、シスター！　これもまた神の恵でしょう！","ENG":"Thank you! This, too, must be a blessing from the Lord!","TWN":"謝謝你！這也是主的恩典吧！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그럼, 즐거운 성탄절 보내세요! 메리 크리스마스! 저는 볼일이 있어서 이만……!","JPN":"では、楽しい聖誕祭をお迎えください、メリークリスマス！　私は用事がありますから、これで……！","ENG":"Then, happy holidays! Merry Christmas! There is something that I must attend to, so...!","TWN":"那麼，祝你聖誕快樂！我有事要先走了……！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L34_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"넬슨 자매님…….","JPN":"シスター・ネルソン……","ENG":"Sister Nelson...","TWN":"尼爾森姊妹……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"메리 크리스마스는 아직 너무 이른걸요…….","JPN":"メリークリスマスはまだまだ早いです……","ENG":"It's too early to be saying \\"Merry Christmas\\"...","TWN":"現在說聖誕快樂還太早了……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};